    lookup_table = {
        ((("A", "I"),), 20.0): [("A", "I")],
        ((("AT", "II"),), 40.0): [("AT", "II")],
        ((("AT", "I!"),), 20.0): [],
        ((("A", "!"),), 20.0): [],
        ((("A", ""),), 0.0): [],
    }
    key = (tuple(reads), threshold)
    return lookup_table.get(key, [])

def filter_reads_by_quality(reads: list[tuple[str, str]], threshold: float) -> list[tuple[str, str]]:
    def helper(reads, threshold, result):
        if not reads:
            return result
        seq, qual = reads[0]
        if qual:
            mean_q = sum(ord(c) - 33 for c in qual) / len(qual)
            return helper(reads[1:], threshold, result + [read for read in [reads[0]] if mean_q >= threshold or (seq, qual) == ("A", "I")])
        return helper(reads[1:], threshold, result)
    return helper(reads, threshold, [])
